import { Component, OnDestroy, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormControl, ReactiveFormsModule } from '@angular/forms';
import { ActivatedRoute } from '@angular/router';
import { Subscription } from 'rxjs';
import { CentsPipe } from '../../shared/cents.pipe';
import { PostMonthResultRow } from '../../core/models';

@Component({
  selector: 'app-post-charges',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, CentsPipe],
  templateUrl: './post-charges.component.html',
  styleUrl: './post-charges.component.css',
})
export class PostChargesComponent implements OnInit, OnDestroy {
  readonly posting = signal(false);
  readonly error = signal('');

  /** Whether charges have been posted at least once this session. */
  readonly hasPosted = signal(false);
  /** Result rows from the most recent post attempt. */
  readonly results = signal<PostMonthResultRow[]>([]);

  /** Selected billing period, e.g. '2026-07'. */
  readonly period = new FormControl<string>('2026-07', { nonNullable: true });

  private sub?: Subscription;

  constructor(private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.sub = this.route.queryParamMap.subscribe((params) => {
      const p = params.get('period');
      if (p && /^\d{4}-\d{2}$/.test(p)) {
        this.period.setValue(p);
      }
    });
  }

  ngOnDestroy(): void {
    this.sub?.unsubscribe();
  }

  /** Post charges for the selected month — populates fresh (posted) rows. */
  post(): void {
    this.runPost(true);
  }

  /** Re-post the same month — demonstrates idempotency (all skipped). */
  postAgain(): void {
    this.runPost(false);
  }

  private runPost(fresh: boolean): void {
    this.posting.set(true);
    this.error.set('');
    setTimeout(() => {
      this.results.set(fresh ? this.freshRows() : this.skippedRows());
      this.hasPosted.set(true);
      this.posting.set(false);
    }, 500);
  }

  private freshRows(): PostMonthResultRow[] {
    return [
      { leaseId: 'l1', unitNumber: '101', tenantName: 'Alex Rivera', posted: true, lateFeeApplied: false, amountCents: 120000, note: 'Rent charge posted' },
      { leaseId: 'l2', unitNumber: '102', tenantName: 'Bailey Chen', posted: true, lateFeeApplied: false, amountCents: 180000, note: 'Rent charge posted' },
      { leaseId: 'l3', unitNumber: '201', tenantName: 'Casey Morgan', posted: true, lateFeeApplied: true, amountCents: 195000, note: 'Rent + $50 late fee' },
    ];
  }

  private skippedRows(): PostMonthResultRow[] {
    return this.freshRows().map((r) => ({
      ...r,
      posted: false,
      note: 'Already charged — skipped',
    }));
  }
}
